#include<bits/stdc++.h>
using namespace std;
bool a[101][101];
int n,m,ant;
double fen;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            int c;
            cin>>c;
            if(!(c^a[i][j])) ant++;
        }
    }
    fen=ant/1.0/(n*m);
    fen*=100;
    printf("%.2lf",fen);
    return 0;
}
